type seasonJoins[Q dialect.Joinable] struct {
	typ         string
	Events      modAs[Q, eventColumns]
	PointSystem modAs[Q, pointSystemColumns]
	Series      modAs[Q, seriesColumns]
	Teams       modAs[Q, teamColumns]
}

func (j seasonJoins[Q]) aliasedAs(alias string) seasonJoins[Q] {
	return buildSeasonJoins[Q](buildSeasonColumns(alias), j.typ)
}

func buildSeasonJoins[Q dialect.Joinable](cols seasonColumns, typ string) seasonJoins[Q] {
	return seasonJoins[Q]{
		typ: typ,
		Events: modAs[Q, eventColumns]{
			c: Events.Columns,
			f: func(to eventColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Events.Name().As(to.Alias())).On(
						to.SeasonID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
		PointSystem: modAs[Q, pointSystemColumns]{
			c: PointSystems.Columns,
			f: func(to pointSystemColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, PointSystems.Name().As(to.Alias())).On(
						to.ID.EQ(cols.PointSystemID),
					))
				}

				return mods
			},
		},
		Series: modAs[Q, seriesColumns]{
			c: Serieses.Columns,
			f: func(to seriesColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Serieses.Name().As(to.Alias())).On(
						to.ID.EQ(cols.SeriesID),
					))
				}

				return mods
			},
		},
		Teams: modAs[Q, teamColumns]{
			c: Teams.Columns,
			f: func(to teamColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Teams.Name().As(to.Alias())).On(
						to.SeasonID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
	}
}
